from flask import Flask, request
from prometheus_client import Counter, generate_latest, REGISTRY
import hashlib

app = Flask(__name__)

# Create a Counter metric with labels for user_id, session_id, and a hashed request path
http_requests_total = Counter(
    'http_requests_total', 
    'Total HTTP Requests',
    ['user_id', 'session_id', 'hashed_path']
)

def hash_path(path):
    # Hash the request path to prevent cardinality explosion
    return hashlib.sha256(path.encode('utf-8')).hexdigest()

@app.route('/metrics')
def metrics():
    return generate_latest(REGISTRY)

@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def track_request(path):
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    hashed_path = hash_path(path)
    
    # Increment the counter with the hashed path
    http_requests_total.labels(user_id=user_id, session_id=session_id, hashed_path=hashed_path).inc()
    
    return "Request tracked"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)